import{_ as e,o as s,c as n,ag as t}from"./chunks/framework.DL0AyVxm.js";const h=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md"}'),i={name:"guide/getting-started.md"};function o(p,a,l,r,c,d){return s(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h1><p>This guide walks you through installing Worclaude and scaffolding a complete Claude Code workflow into a project from scratch.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>Before you begin, make sure you have:</p><ul><li><strong>Node.js 18 or later</strong> -- Worclaude is a Node.js CLI tool. Check your version with <code>node --version</code>.</li><li><strong>Claude Code installed</strong> -- Worclaude generates configuration files for Claude Code. You will need Claude Code to actually use the workflow. See <a href="https://docs.anthropic.com/en/docs/claude-code" target="_blank" rel="noreferrer">Claude Code documentation</a> for installation.</li></ul><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><p>Install Worclaude globally from npm:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> worclaude</span></span></code></pre></div><p>Verify it installed correctly:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">worclaude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div><p>You should see output like:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1.1.0</span></span></code></pre></div><h2 id="creating-your-project" tabindex="-1">Creating Your Project <a class="header-anchor" href="#creating-your-project" aria-label="Permalink to &quot;Creating Your Project&quot;">​</a></h2><p>Navigate to an existing project directory, or create a new one:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-project</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-project</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span></span></code></pre></div><p>Worclaude works with any project -- it does not require a specific language, framework, or structure. It works equally well in a brand new empty directory or in an existing codebase.</p><h2 id="running-worclaude-init" tabindex="-1">Running <code>worclaude init</code> <a class="header-anchor" href="#running-worclaude-init" aria-label="Permalink to &quot;Running \`worclaude init\`&quot;">​</a></h2><p>Start the interactive setup:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">worclaude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span></span></code></pre></div><p>You will see the Worclaude header and the first prompt:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  Worclaude v1.1.0</span></span>
<span class="line"><span>  ─────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>? Project name: my-project</span></span>
<span class="line"><span>? One-line description: A web app for managing tasks</span></span></code></pre></div><p>The project name defaults to the current directory name. The description is used in generated files like <code>CLAUDE.md</code> and <code>SPEC.md</code>.</p><h2 id="step-1-project-type" tabindex="-1">Step 1: Project Type <a class="header-anchor" href="#step-1-project-type" aria-label="Permalink to &quot;Step 1: Project Type&quot;">​</a></h2><p>Next, you select what kind of project you are building. This is a multi-select prompt -- use <strong>Space</strong> to toggle options and <strong>Enter</strong> to confirm:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>? What type of project is this? (space to toggle, enter to confirm)</span></span>
<span class="line"><span>  ◻ Full-stack web application — Frontend + backend in one repo</span></span>
<span class="line"><span>  ◻ Backend / API              — Server, REST/GraphQL, no frontend</span></span>
<span class="line"><span>  ◻ Frontend / UI              — Client-side app, no backend</span></span>
<span class="line"><span>  ◻ CLI tool                   — Command-line application</span></span>
<span class="line"><span>  ◻ Data / ML / AI             — Data pipelines, ML models, LLM apps</span></span>
<span class="line"><span>  ◻ Library / Package          — Reusable module published to npm/PyPI</span></span>
<span class="line"><span>  ◻ DevOps / Infrastructure    — Infrastructure, CI/CD, deployment</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  ℹ Not sure? Pick what&#39;s closest. You can add or remove</span></span>
<span class="line"><span>    agents later with \`worclaude upgrade\`.</span></span></code></pre></div><p>You can select multiple types. If you pick &quot;Full-stack web application&quot; along with &quot;Backend / API&quot; or &quot;Frontend / UI&quot;, Worclaude will warn you about the overlap since full-stack already includes both.</p><p>Your project type selection determines which agent categories are pre-selected in the next step. For example, selecting &quot;Backend / API&quot; pre-selects the Backend and Quality agent categories.</p><h2 id="step-2-tech-stack" tabindex="-1">Step 2: Tech Stack <a class="header-anchor" href="#step-2-tech-stack" aria-label="Permalink to &quot;Step 2: Tech Stack&quot;">​</a></h2><p>Select your primary languages and runtimes. Again, this is a multi-select:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>? Primary language(s) / runtime: (space to toggle, enter to confirm)</span></span>
<span class="line"><span>  ◻ Python</span></span>
<span class="line"><span>  ◻ Node.js / TypeScript</span></span>
<span class="line"><span>  ◻ Java</span></span>
<span class="line"><span>  ◻ C# / .NET</span></span>
<span class="line"><span>  ◻ C / C++</span></span>
<span class="line"><span>  ◻ Go</span></span>
<span class="line"><span>  ◻ PHP</span></span>
<span class="line"><span>  ◻ Ruby</span></span>
<span class="line"><span>  ◻ Kotlin</span></span>
<span class="line"><span>  ◻ Swift</span></span>
<span class="line"><span>  ◻ Rust</span></span>
<span class="line"><span>  ◻ Dart / Flutter</span></span>
<span class="line"><span>  ◻ Scala</span></span>
<span class="line"><span>  ◻ Elixir</span></span>
<span class="line"><span>  ◻ Zig</span></span>
<span class="line"><span>  ◻ Other / None</span></span></code></pre></div><p>After selecting languages, you will be asked about Docker:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>? Do you use Docker in this project currently? (y/N)</span></span></code></pre></div><p>Your tech stack selection determines:</p><ul><li><strong>Permissions</strong> in <code>settings.json</code> (e.g., Python projects get <code>Bash(pip:*)</code> and <code>Bash(python:*)</code>)</li><li><strong>Formatter hooks</strong> (e.g., Python uses <code>ruff format .</code>, Node.js uses <code>npx prettier --write .</code>)</li><li><strong>Commands block</strong> in <code>CLAUDE.md</code> (test, lint, and format commands for your stack)</li></ul><p>When you select multiple languages, all permissions are merged and formatters are chained together.</p><h2 id="step-3-agent-selection" tabindex="-1">Step 3: Agent Selection <a class="header-anchor" href="#step-3-agent-selection" aria-label="Permalink to &quot;Step 3: Agent Selection&quot;">​</a></h2><p>This is a two-step process. First, you select agent <strong>categories</strong>. The categories are pre-selected based on your project type:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✓ Universal agents (always installed):</span></span>
<span class="line"><span>  ✓ plan-reviewer</span></span>
<span class="line"><span>  ✓ code-simplifier</span></span>
<span class="line"><span>  ✓ test-writer</span></span>
<span class="line"><span>  ✓ build-validator</span></span>
<span class="line"><span>  ✓ verify-app</span></span>
<span class="line"><span></span></span>
<span class="line"><span>? Which agent categories do you need? (space to toggle)</span></span>
<span class="line"><span>  ◼ Backend         — api-designer, database-analyst, auth-auditor</span></span>
<span class="line"><span>  ◻ Frontend        — ui-reviewer, style-enforcer</span></span>
<span class="line"><span>  ◻ DevOps          — ci-fixer, docker-helper, deploy-validator, dependency-manager</span></span>
<span class="line"><span>  ◼ Quality         — bug-fixer, security-reviewer, performance-auditor, refactorer</span></span>
<span class="line"><span>  ◻ Documentation   — doc-writer, changelog-generator</span></span>
<span class="line"><span>  ◻ Data / AI       — data-pipeline-reviewer, ml-experiment-tracker, prompt-engineer</span></span></code></pre></div><p>The 5 universal agents are always installed. Then, for each category you selected, you can fine-tune which specific agents to include:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>? Fine-tune Backend agents? (space to toggle, enter to accept defaults)</span></span>
<span class="line"><span>  ◼ api-designer       — Reviews API design for RESTful conventions</span></span>
<span class="line"><span>  ◼ database-analyst    — Reviews database schemas and queries</span></span>
<span class="line"><span>  ◼ auth-auditor        — Audits authentication and authorization</span></span></code></pre></div><p>Press <strong>Enter</strong> to accept all the defaults, or toggle individual agents off if you do not need them.</p><h2 id="step-4-confirmation" tabindex="-1">Step 4: Confirmation <a class="header-anchor" href="#step-4-confirmation" aria-label="Permalink to &quot;Step 4: Confirmation&quot;">​</a></h2><p>Before anything is written to disk, Worclaude shows a review summary:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  ─── Review Your Selections ───</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Project:    my-project — A web app for managing tasks</span></span>
<span class="line"><span>  Type:       Backend / API</span></span>
<span class="line"><span>  Stack:      Python, Docker</span></span>
<span class="line"><span>  Agents:     5 universal + 6 optional (11 total)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>? Everything look right?</span></span>
<span class="line"><span>  ◉ Yes, install the workflow</span></span>
<span class="line"><span>  ○ No, let me start over</span></span>
<span class="line"><span>  ○ Let me adjust a specific step</span></span></code></pre></div><p>If you choose &quot;Let me adjust a specific step&quot;, you can go back and change just one part (project info, project type, tech stack, or agents) without redoing everything.</p><h2 id="step-5-scaffolding" tabindex="-1">Step 5: Scaffolding <a class="header-anchor" href="#step-5-scaffolding" aria-label="Permalink to &quot;Step 5: Scaffolding&quot;">​</a></h2><p>Once you confirm, Worclaude creates all the files:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  Creating workflow structure...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  ✓ CLAUDE.md</span></span>
<span class="line"><span>  ✓ .claude/settings.json</span></span>
<span class="line"><span>  ✓ .claude/workflow-meta.json</span></span>
<span class="line"><span>  ✓ .claude/agents/ (5 universal + 6 optional)</span></span>
<span class="line"><span>  ✓ .claude/commands/ (10)</span></span>
<span class="line"><span>  ✓ .claude/skills/ (9 universal + 3 templates)</span></span>
<span class="line"><span>  ✓ .mcp.json</span></span>
<span class="line"><span>  ✓ docs/spec/PROGRESS.md</span></span>
<span class="line"><span>  ✓ docs/spec/SPEC.md</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Workflow installed successfully!</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  What to do next:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  1. Start a Claude Code session in this project</span></span>
<span class="line"><span>  2. Run /setup — Claude will interview you about your project</span></span>
<span class="line"><span>     and fill in all configuration files automatically</span></span>
<span class="line"><span>  3. Review CLAUDE.md and adjust if needed</span></span>
<span class="line"><span>  4. Start building!</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Tip: The /setup command is the fastest way to configure</span></span>
<span class="line"><span>  your project. It takes about 5 minutes.</span></span></code></pre></div><p>If <code>docs/spec/PROGRESS.md</code> or <code>docs/spec/SPEC.md</code> already exist in your project, Worclaude skips them rather than overwriting your content.</p><h2 id="understanding-the-output" tabindex="-1">Understanding the Output <a class="header-anchor" href="#understanding-the-output" aria-label="Permalink to &quot;Understanding the Output&quot;">​</a></h2><p>Here is what was created:</p><table tabindex="0"><thead><tr><th>File / Directory</th><th>Purpose</th></tr></thead><tbody><tr><td><code>CLAUDE.md</code></td><td>Main instruction file for Claude Code. Under 50 lines, with progressive disclosure via skills.</td></tr><tr><td><code>.claude/settings.json</code></td><td>Permissions, hooks (auto-format, post-compact, notification), and sandbox configuration.</td></tr><tr><td><code>.claude/workflow-meta.json</code></td><td>Internal metadata: version, selected options, file hashes for upgrade detection.</td></tr><tr><td><code>.claude/agents/</code></td><td>Agent definition files. Each agent specifies a model (Opus/Sonnet/Haiku) and isolation mode.</td></tr><tr><td><code>.claude/commands/</code></td><td>Slash command files. Used as <code>/start</code>, <code>/end</code>, <code>/verify</code>, etc. inside Claude Code.</td></tr><tr><td><code>.claude/skills/</code></td><td>Knowledge files Claude loads on demand. Universal skills plus templates for your project.</td></tr><tr><td><code>.mcp.json</code></td><td>MCP (Model Context Protocol) server configuration.</td></tr><tr><td><code>docs/spec/PROGRESS.md</code></td><td>Session progress tracking. Claude reads this at the start of every session.</td></tr><tr><td><code>docs/spec/SPEC.md</code></td><td>Project specification template. Your source of truth for features and requirements.</td></tr></tbody></table><h2 id="launching-claude-code" tabindex="-1">Launching Claude Code <a class="header-anchor" href="#launching-claude-code" aria-label="Permalink to &quot;Launching Claude Code&quot;">​</a></h2><p>With the workflow installed, start Claude Code:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --worktree</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tmux</span></span></code></pre></div><p>The flags are recommended by Boris Cherny&#39;s workflow:</p><ul><li><code>--worktree</code> enables git worktree isolation, so agents like code-simplifier and test-writer can work in parallel without conflicts.</li><li><code>--tmux</code> runs Claude in a tmux session, so you can detach and reattach without losing your session.</li></ul><h2 id="running-setup" tabindex="-1">Running <code>/setup</code> <a class="header-anchor" href="#running-setup" aria-label="Permalink to &quot;Running \`/setup\`&quot;">​</a></h2><p>The first thing you should do in your new Claude Code session is run the <code>/setup</code> command:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; /setup</span></span></code></pre></div><p>This starts a conversational interview where Claude asks you about your project across 7 sections: Project Story, Architecture, Tech Stack Details, Core Features, Development Workflow, Coding Conventions, and Verification Strategy.</p><p>Based on your answers, <code>/setup</code> automatically fills in:</p><ul><li><code>CLAUDE.md</code> with your real tech stack, commands, and project description</li><li><code>SPEC.md</code> with your features and requirements</li><li><code>backend-conventions.md</code> with your backend patterns</li><li><code>frontend-design-system.md</code> with your design system details</li><li><code>project-patterns.md</code> with your architectural patterns</li><li><code>PROGRESS.md</code> with your current state</li></ul><p>The whole process takes about 5 minutes and replaces all the placeholder content with real, project-specific configuration.</p><h2 id="verifying-everything-works" tabindex="-1">Verifying Everything Works <a class="header-anchor" href="#verifying-everything-works" aria-label="Permalink to &quot;Verifying Everything Works&quot;">​</a></h2><p>After <code>/setup</code> completes, verify the workflow is functioning:</p><ol><li>Run <code>/status</code> to see your current session state</li><li>Run <code>/verify</code> to confirm your build and tests pass</li><li>Check that <code>CLAUDE.md</code> contains your actual project details</li><li>Check that auto-formatting works by making a small edit</li></ol><p>If everything looks good, you are ready to start building. See the <a href="/Worclaude/guide/workflow-tips.html">Workflow Tips</a> guide for best practices on working with Claude Code after setup.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/Worclaude/guide/existing-projects.html">Existing Projects</a> -- If you already have Claude Code configured, read this instead</li><li><a href="/Worclaude/guide/upgrading.html">Upgrading</a> -- How to update when new Worclaude versions are released</li><li><a href="/Worclaude/guide/workflow-tips.html">Workflow Tips</a> -- Best practices for getting the most out of your workflow</li></ul>`,70)])])}const g=e(i,[["render",o]]);export{h as __pageData,g as default};
